from trading_ai.scanner.dashboard import DashboardConfiguration,DashboardEventType,DashboardView,RankingRecord,ScannerDashboardEngine,ScannerStatus
def main():
 e=ScannerDashboardEngine(); s=e.create_snapshot(DashboardConfiguration(top_n=10)); assert s.session.status is ScannerStatus.IDLE; s=e.initialize_universe(s,universe_name='TEST',universe_size=100); s=e.start_scan(s); s=e.update_progress(s,symbols_completed=40,symbols_failed=2,symbols_skipped=3,elapsed_seconds=10); assert s.progress.symbols_remaining==55 and s.progress.symbols_per_second==4.5 and s.progress.completion_pct==45.0; s=e.update_rankings(s,[RankingRecord('MSFT',2,.89,.72),RankingRecord('AAPL',1,.91,.76)]); assert s.rankings[0].symbol=='AAPL'; s=e.navigate(s,DashboardView.CANDIDATE,'AAPL'); assert s.events[-1].event_type is DashboardEventType.CANDIDATE_OPENED; s=e.complete_scan(s); assert s.session.status is ScannerStatus.COMPLETED; print('Milestone 35 Phase 5 Step 1 engine assertions passed.')
if __name__=='__main__': main()
